/**
 * User notification preferences model.
 *
 * Controls how and when a user receives notifications across multiple channels
 * (email, SMS, webhook). Each user has one preferences record; if none exists,
 * defaults apply (email enabled with all notifications, SMS/webhook disabled).
 *
 * History: Originally email-only (Agent 3). Extended to multi-channel (Agent 9)
 * after SMS support was added (Agent 8) and webhook adapter existed (Agent 6).
 * The email-only assumption is no longer valid — preferences are now per-channel.
 */

import type { NotificationType } from './notification.js';

/** How often email digests are sent. */
export type EmailFrequency = 'immediate' | 'daily' | 'weekly';

/**
 * Per-category subscription setting.
 * Users can opt out of specific notification types.
 */
export interface CategorySubscription {
  type: NotificationType;
  enabled: boolean;
}

/**
 * Email-specific notification preferences.
 */
export interface EmailPreferences {
  enabled: boolean;
  frequency: EmailFrequency;
  categories: CategorySubscription[];
}

/**
 * SMS-specific notification preferences.
 * Defaults to disabled (opt-in) since a phone number must be explicitly provided.
 */
export interface SmsPreferences {
  enabled: boolean;
  phoneNumber: string;
  categories: CategorySubscription[];
}

/**
 * Webhook-specific notification preferences.
 * Defaults to disabled (opt-in) since a webhook URL must be explicitly provided.
 */
export interface WebhookPreferences {
  enabled: boolean;
  url: string;
  categories: CategorySubscription[];
}

/**
 * Top-level user notification preferences.
 * Each channel is optional — missing channels use defaults.
 */
export interface UserPreferences {
  id: string;
  userId: string;
  email: EmailPreferences;
  sms?: SmsPreferences;
  webhook?: WebhookPreferences;
  createdAt: Date;
  updatedAt: Date;
}

/**
 * Input for creating user preferences.
 */
export interface CreateUserPreferencesInput {
  userId: string;
  email?: Partial<EmailPreferences>;
  sms?: Partial<SmsPreferences>;
  webhook?: Partial<WebhookPreferences>;
}

/**
 * Input for updating user preferences.
 */
export interface UpdateUserPreferencesInput {
  email?: Partial<EmailPreferences>;
  sms?: Partial<SmsPreferences>;
  webhook?: Partial<WebhookPreferences>;
}

/** All known notification types for building default subscriptions. */
const ALL_NOTIFICATION_TYPES: NotificationType[] = [
  'order_confirmation',
  'order_status_update',
  'user_welcome',
  'user_update',
  'system_alert',
];

/**
 * Build default email preferences: all categories enabled, immediate delivery.
 */
export function defaultEmailPreferences(): EmailPreferences {
  return {
    enabled: true,
    frequency: 'immediate',
    categories: ALL_NOTIFICATION_TYPES.map((type) => ({ type, enabled: true })),
  };
}

/**
 * Build default SMS preferences: disabled (opt-in), no phone number.
 */
export function defaultSmsPreferences(): SmsPreferences {
  return {
    enabled: false,
    phoneNumber: '',
    categories: ALL_NOTIFICATION_TYPES.map((type) => ({ type, enabled: true })),
  };
}

/**
 * Build default webhook preferences: disabled (opt-in), no URL.
 */
export function defaultWebhookPreferences(): WebhookPreferences {
  return {
    enabled: false,
    url: '',
    categories: ALL_NOTIFICATION_TYPES.map((type) => ({ type, enabled: true })),
  };
}

/**
 * Repository for UserPreferences data access.
 *
 * Extends BaseRepository with preference-specific query methods.
 * Flattens per-channel preferences into individual database fields.
 */

import type { DatabaseRecord } from '../utils/database.js';
import type { Database } from '../utils/database.js';
import type {
  UserPreferences,
  CategorySubscription,
  SmsPreferences,
  WebhookPreferences,
} from '../models/user-preferences.js';
import { BaseRepository } from './base.repository.js';

export class PreferencesRepository extends BaseRepository<UserPreferences> {
  constructor(db: Database) {
    super(db, 'user_preferences');
  }

  protected toDomain(record: DatabaseRecord): UserPreferences {
    const prefs: UserPreferences = {
      id: record['id'] as string,
      userId: record['userId'] as string,
      email: {
        enabled: record['emailEnabled'] as boolean,
        frequency: record['emailFrequency'] as UserPreferences['email']['frequency'],
        categories: JSON.parse(record['emailCategories'] as string) as CategorySubscription[],
      },
      createdAt: new Date(record['createdAt'] as string),
      updatedAt: new Date(record['updatedAt'] as string),
    };

    // Hydrate SMS preferences if present
    if (record['smsEnabled'] !== undefined) {
      prefs.sms = {
        enabled: record['smsEnabled'] as boolean,
        phoneNumber: record['smsPhoneNumber'] as string,
        categories: JSON.parse(record['smsCategories'] as string) as CategorySubscription[],
      };
    }

    // Hydrate webhook preferences if present
    if (record['webhookEnabled'] !== undefined) {
      prefs.webhook = {
        enabled: record['webhookEnabled'] as boolean,
        url: record['webhookUrl'] as string,
        categories: JSON.parse(record['webhookCategories'] as string) as CategorySubscription[],
      };
    }

    return prefs;
  }

  protected toRecord(entity: UserPreferences): DatabaseRecord {
    const record: DatabaseRecord = {
      id: entity.id,
      userId: entity.userId,
      emailEnabled: entity.email.enabled,
      emailFrequency: entity.email.frequency,
      emailCategories: JSON.stringify(entity.email.categories),
      createdAt: entity.createdAt.toISOString(),
      updatedAt: entity.updatedAt.toISOString(),
    };

    if (entity.sms) {
      record['smsEnabled'] = entity.sms.enabled;
      record['smsPhoneNumber'] = entity.sms.phoneNumber;
      record['smsCategories'] = JSON.stringify(entity.sms.categories);
    }

    if (entity.webhook) {
      record['webhookEnabled'] = entity.webhook.enabled;
      record['webhookUrl'] = entity.webhook.url;
      record['webhookCategories'] = JSON.stringify(entity.webhook.categories);
    }

    return record;
  }

  /**
   * Find preferences by user ID.
   */
  findByUserId(userId: string): UserPreferences | undefined {
    const results = this.findAll((prefs) => prefs.userId === userId);
    return results[0];
  }
}

/**
 * Preferences service — manages user notification preferences.
 *
 * Provides CRUD for user preferences and lookup methods used by
 * NotificationService to check whether a notification should be sent
 * on a given channel.
 *
 * Supports per-channel preferences: email (default on), SMS (default off),
 * webhook (default off). The shouldSendToChannel() method provides a
 * unified interface for all channels.
 *
 * Depends on:
 * - PreferencesRepository for data access
 */

import type { PreferencesRepository } from '../repositories/preferences.repository.js';
import type {
  UserPreferences,
  CreateUserPreferencesInput,
  UpdateUserPreferencesInput,
  SmsPreferences,
  WebhookPreferences,
} from '../models/user-preferences.js';
import type { NotificationType, NotificationChannel } from '../models/notification.js';
import {
  defaultEmailPreferences,
  defaultSmsPreferences,
  defaultWebhookPreferences,
} from '../models/user-preferences.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generatePreferencesId(): string {
  return `pref-${String(nextId++).padStart(4, '0')}`;
}

export function resetPreferencesIdCounter(): void {
  nextId = 1;
}

export class PreferencesService {
  private logger = new Logger('PreferencesService');

  constructor(private preferencesRepository: PreferencesRepository) {}

  /**
   * Create preferences for a user. Partial settings for any channel
   * are merged with defaults.
   */
  createPreferences(input: CreateUserPreferencesInput): UserPreferences {
    const existing = this.preferencesRepository.findByUserId(input.userId);
    if (existing) {
      throw new Error(`Preferences already exist for user: ${input.userId}`);
    }

    const emailDefaults = defaultEmailPreferences();
    const emailPrefs = input.email
      ? {
          enabled: input.email.enabled ?? emailDefaults.enabled,
          frequency: input.email.frequency ?? emailDefaults.frequency,
          categories: input.email.categories ?? emailDefaults.categories,
        }
      : emailDefaults;

    const preferences: UserPreferences = {
      id: generatePreferencesId(),
      userId: input.userId,
      email: emailPrefs,
      createdAt: new Date(),
      updatedAt: new Date(),
    };

    // Only set SMS preferences if explicitly provided
    if (input.sms) {
      const smsDefaults = defaultSmsPreferences();
      preferences.sms = {
        enabled: input.sms.enabled ?? smsDefaults.enabled,
        phoneNumber: input.sms.phoneNumber ?? smsDefaults.phoneNumber,
        categories: input.sms.categories ?? smsDefaults.categories,
      };
    }

    // Only set webhook preferences if explicitly provided
    if (input.webhook) {
      const webhookDefaults = defaultWebhookPreferences();
      preferences.webhook = {
        enabled: input.webhook.enabled ?? webhookDefaults.enabled,
        url: input.webhook.url ?? webhookDefaults.url,
        categories: input.webhook.categories ?? webhookDefaults.categories,
      };
    }

    this.preferencesRepository.save(preferences);
    this.logger.info(`Created preferences ${preferences.id} for user ${input.userId}`);
    return preferences;
  }

  /**
   * Get preferences for a user. Returns undefined if none exist.
   */
  getPreferences(userId: string): UserPreferences | undefined {
    return this.preferencesRepository.findByUserId(userId);
  }

  /**
   * Update preferences for a user. Merges partial channel settings
   * with existing values.
   */
  updatePreferences(userId: string, input: UpdateUserPreferencesInput): UserPreferences {
    const existing = this.preferencesRepository.findByUserId(userId);
    if (!existing) {
      throw new Error(`Preferences not found for user: ${userId}`);
    }

    const updatedEmail = input.email
      ? {
          enabled: input.email.enabled ?? existing.email.enabled,
          frequency: input.email.frequency ?? existing.email.frequency,
          categories: input.email.categories ?? existing.email.categories,
        }
      : existing.email;

    const updates: Partial<UserPreferences> = {
      email: updatedEmail,
      updatedAt: new Date(),
    };

    // Update SMS preferences if provided
    if (input.sms) {
      const existingSms = existing.sms ?? defaultSmsPreferences();
      updates.sms = {
        enabled: input.sms.enabled ?? existingSms.enabled,
        phoneNumber: input.sms.phoneNumber ?? existingSms.phoneNumber,
        categories: input.sms.categories ?? existingSms.categories,
      };
    } else if (existing.sms) {
      updates.sms = existing.sms;
    }

    // Update webhook preferences if provided
    if (input.webhook) {
      const existingWebhook = existing.webhook ?? defaultWebhookPreferences();
      updates.webhook = {
        enabled: input.webhook.enabled ?? existingWebhook.enabled,
        url: input.webhook.url ?? existingWebhook.url,
        categories: input.webhook.categories ?? existingWebhook.categories,
      };
    } else if (existing.webhook) {
      updates.webhook = existing.webhook;
    }

    const updated = this.preferencesRepository.update(existing.id, updates);

    this.logger.info(`Updated preferences for user ${userId}`);
    return updated;
  }

  /**
   * Delete preferences for a user.
   */
  deletePreferences(userId: string): boolean {
    const existing = this.preferencesRepository.findByUserId(userId);
    if (!existing) {
      return false;
    }
    this.preferencesRepository.delete(existing.id);
    this.logger.info(`Deleted preferences for user ${userId}`);
    return true;
  }

  /**
   * Check whether a notification should be sent to a user via email.
   *
   * Returns true if:
   * - The user has no preferences (defaults allow all)
   * - Email is enabled AND the notification type is subscribed
   *
   * Returns false if:
   * - Email is globally disabled
   * - The specific notification type is disabled
   */
  shouldSendEmail(userId: string, notificationType: NotificationType): boolean {
    return this.checkChannelPreferences(userId, 'email', notificationType);
  }

  /**
   * Check whether a notification should be sent to a user via SMS.
   *
   * Returns false by default (opt-in) — SMS preferences must be explicitly
   * created with enabled=true and a phone number.
   */
  shouldSendSms(userId: string, notificationType: NotificationType): boolean {
    return this.checkChannelPreferences(userId, 'sms', notificationType);
  }

  /**
   * Check whether a notification should be sent to a user via webhook.
   *
   * Returns false by default (opt-in) — webhook preferences must be
   * explicitly created with enabled=true and a URL.
   */
  shouldSendWebhook(userId: string, notificationType: NotificationType): boolean {
    return this.checkChannelPreferences(userId, 'webhook', notificationType);
  }

  /**
   * Unified channel preference check. Used by NotificationService to determine
   * whether to send a notification on a given channel.
   *
   * Channel behavior:
   * - email: default-allow (send unless explicitly disabled)
   * - sms: default-deny (don't send unless explicitly enabled with phone number)
   * - webhook: default-deny (don't send unless explicitly enabled with URL)
   * - in-app: default-allow (always send, no preference check needed)
   */
  shouldSendToChannel(
    userId: string,
    channel: NotificationChannel,
    notificationType: NotificationType,
  ): boolean {
    return this.checkChannelPreferences(userId, channel, notificationType);
  }

  private checkChannelPreferences(
    userId: string,
    channel: NotificationChannel,
    notificationType: NotificationType,
  ): boolean {
    const prefs = this.preferencesRepository.findByUserId(userId);

    if (channel === 'email') {
      // No preferences = default: send everything via email
      if (!prefs) {
        return true;
      }
      if (!prefs.email.enabled) {
        return false;
      }
      const category = prefs.email.categories.find((c) => c.type === notificationType);
      return !category || category.enabled;
    }

    if (channel === 'sms') {
      // No preferences or no SMS config = default: don't send (opt-in)
      if (!prefs || !prefs.sms) {
        return false;
      }
      if (!prefs.sms.enabled) {
        return false;
      }
      const category = prefs.sms.categories.find((c) => c.type === notificationType);
      return !category || category.enabled;
    }

    if (channel === 'webhook') {
      // No preferences or no webhook config = default: don't send (opt-in)
      if (!prefs || !prefs.webhook) {
        return false;
      }
      if (!prefs.webhook.enabled) {
        return false;
      }
      const category = prefs.webhook.categories.find((c) => c.type === notificationType);
      return !category || category.enabled;
    }

    // in-app and unknown channels: default allow
    return true;
  }
}

/**
 * Notification service — handles sending notifications in response to events.
 *
 * ARCHITECTURE:
 * - All notifications are triggered via EventBus subscriptions (event-driven).
 * - Delivery is routed through NotificationAdapter implementations.
 * - Each adapter handles one channel (email, webhook, sms, etc.).
 * - Register adapters via registerAdapter() before events are emitted.
 * - Per-channel preference checks via PreferencesService.shouldSendToChannel().
 *
 * CONSTRAINTS:
 * - All notifications MUST go through EventBus.emit() — never call
 *   sendNotification() from outside this service.
 * - All delivery channels MUST implement the NotificationAdapter interface.
 * - The service emits notification:sent / notification:failed events
 *   for observability.
 *
 * Depends on:
 * - EventBus (event system) for receiving domain events
 * - NotificationAdapter implementations for delivery
 */

import type { EventBus } from '../events/event-bus.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../events/event-types.js';
import type { NotificationAdapter } from '../adapters/notification.adapter.js';
import type {
  Notification,
  NotificationChannel,
  NotificationPayload,
} from '../models/notification.js';
import type { PreferencesService } from './preferences.service.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generateNotificationId(): string {
  return `notif-${String(nextId++).padStart(4, '0')}`;
}

export function resetNotificationIdCounter(): void {
  nextId = 1;
}

export class NotificationService {
  private logger = new Logger('NotificationService');
  private notifications: Notification[] = [];
  private adapters: Map<NotificationChannel, NotificationAdapter> = new Map();
  private preferencesService: PreferencesService | undefined;

  constructor(private eventBus: EventBus) {
    this.registerHandlers();
  }

  /**
   * Set the preferences service for checking user notification preferences.
   * When set, notifications are filtered according to per-channel user preferences.
   * When not set, all notifications are sent (backward-compatible default).
   */
  setPreferencesService(preferencesService: PreferencesService): void {
    this.preferencesService = preferencesService;
  }

  /**
   * Register a notification adapter for a specific channel.
   * Only one adapter per channel is supported; registering a second
   * adapter for the same channel replaces the first.
   */
  registerAdapter(adapter: NotificationAdapter): void {
    this.logger.info(`Registering adapter for channel: ${adapter.channel}`);
    this.adapters.set(adapter.channel, adapter);
  }

  /**
   * Register event handlers for notification triggers.
   * All handlers use EventBus subscriptions (event-driven pattern).
   */
  private registerHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      return this.handleOrderCreated(event);
    });

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
      return this.handleOrderStatusChanged(event);
    });
  }

  /**
   * Handle order created event — send confirmation to user on all registered channels
   * that the user's preferences allow.
   */
  private async handleOrderCreated(event: OrderCreatedEvent): Promise<void> {
    this.logger.info(`Sending order confirmation for order ${event.order.id}`);

    const itemSummary = event.order.items
      .map((item) => `${item.name} x${item.quantity}`)
      .join(', ');

    const basePayload = {
      recipient: event.user.email,
      subject: `Order Confirmation: ${event.order.id}`,
      body: `Your order has been placed. Items: ${itemSummary}. Total: $${event.order.total.toFixed(2)}`,
      type: 'order_confirmation' as const,
      priority: 'normal' as const,
    };

    // Send to each registered channel, checking per-channel preferences
    for (const [channel] of this.adapters) {
      if (this.preferencesService && !this.preferencesService.shouldSendToChannel(event.user.id, channel, 'order_confirmation')) {
        this.logger.info(`Skipping order confirmation on ${channel} for user ${event.user.id} — disabled by preferences`);
        continue;
      }

      await this.sendNotification({
        ...basePayload,
        channel,
      });
    }

    // Fallback: if no adapters registered, still store notification (backward compat)
    if (this.adapters.size === 0) {
      if (this.preferencesService && !this.preferencesService.shouldSendToChannel(event.user.id, 'email', 'order_confirmation')) {
        this.logger.info(`Skipping order confirmation for user ${event.user.id} — disabled by preferences`);
        return;
      }

      await this.sendNotification({
        ...basePayload,
        channel: 'email',
      });
    }
  }

  /**
   * Handle order status change — notify user of update on all registered channels
   * that the user's preferences allow.
   */
  private async handleOrderStatusChanged(event: OrderStatusChangedEvent): Promise<void> {
    this.logger.info(
      `Sending status update for order ${event.order.id}: ${event.previousStatus} -> ${event.newStatus}`,
    );

    const basePayload = {
      recipient: event.order.userId,
      subject: `Order Update: ${event.order.id}`,
      body: `Your order status has changed from ${event.previousStatus} to ${event.newStatus}.`,
      type: 'order_status_update' as const,
      priority: 'normal' as const,
    };

    // Send to each registered channel, checking per-channel preferences
    for (const [channel] of this.adapters) {
      if (this.preferencesService && !this.preferencesService.shouldSendToChannel(event.order.userId, channel, 'order_status_update')) {
        this.logger.info(`Skipping status update on ${channel} for user ${event.order.userId} — disabled by preferences`);
        continue;
      }

      await this.sendNotification({
        ...basePayload,
        channel,
      });
    }

    // Fallback: if no adapters registered, still store notification (backward compat)
    if (this.adapters.size === 0) {
      if (this.preferencesService && !this.preferencesService.shouldSendToChannel(event.order.userId, 'email', 'order_status_update')) {
        this.logger.info(`Skipping status update for user ${event.order.userId} — disabled by preferences`);
        return;
      }

      await this.sendNotification({
        ...basePayload,
        channel: 'email',
      });
    }
  }

  /**
   * Send a notification through the appropriate adapter.
   * Falls back to in-memory storage if no adapter is registered for the channel.
   */
  private async sendNotification(payload: NotificationPayload): Promise<void> {
    const notification: Notification = {
      id: generateNotificationId(),
      recipient: payload.recipient,
      subject: payload.subject,
      body: payload.body,
      channel: payload.channel,
      type: payload.type,
      priority: payload.priority,
      status: 'pending',
      metadata: payload.metadata,
      sentAt: new Date(),
    };

    const adapter = this.adapters.get(payload.channel);
    if (adapter) {
      const result = await adapter.send(payload);
      notification.status = result.success ? 'sent' : 'failed';

      if (result.success) {
        await this.eventBus.emit({
          type: 'notification:sent',
          notification,
          channel: payload.channel,
          timestamp: new Date(),
        });
      } else {
        await this.eventBus.emit({
          type: 'notification:failed',
          recipient: payload.recipient,
          subject: payload.subject,
          channel: payload.channel,
          error: result.error ?? 'Unknown error',
          timestamp: new Date(),
        });
      }
    } else {
      // No adapter registered — store as sent (in-memory fallback)
      notification.status = 'sent';
    }

    this.notifications.push(notification);
    this.logger.info(`Notification ${notification.id} [${notification.status}] to ${payload.recipient}`);
  }

  /**
   * Get all sent notifications.
   */
  getNotifications(): Notification[] {
    return [...this.notifications];
  }

  /**
   * Get notifications for a specific recipient.
   */
  getNotificationsForRecipient(recipient: string): Notification[] {
    return this.notifications.filter((n) => n.recipient === recipient);
  }

  /**
   * Get the count of sent notifications.
   */
  getNotificationCount(): number {
    return this.notifications.length;
  }

  /**
   * Clear all notifications (useful for testing).
   */
  clearNotifications(): void {
    this.notifications = [];
  }
}

