import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { PreferencesRepository } from '../../src/repositories/preferences.repository.js';
import {
  PreferencesService,
  resetPreferencesIdCounter,
} from '../../src/services/preferences.service.js';
import { EventBus } from '../../src/events/event-bus.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import { EmailAdapter } from '../../src/adapters/email.adapter.js';
import { SmsAdapter } from '../../src/adapters/sms.adapter.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';

describe('PreferencesService', () => {
  let db: Database;
  let repo: PreferencesRepository;
  let service: PreferencesService;

  beforeEach(() => {
    db = new Database();
    repo = new PreferencesRepository(db);
    service = new PreferencesService(repo);
    resetPreferencesIdCounter();
  });

  describe('createPreferences', () => {
    it('should create preferences with defaults when no email config given', () => {
      const prefs = service.createPreferences({ userId: 'user-1' });

      expect(prefs.id).toBe('pref-0001');
      expect(prefs.userId).toBe('user-1');
      expect(prefs.email.enabled).toBe(true);
      expect(prefs.email.frequency).toBe('immediate');
      expect(prefs.email.categories).toHaveLength(5);
      expect(prefs.email.categories.every((c) => c.enabled)).toBe(true);
    });

    it('should merge partial email settings with defaults', () => {
      const prefs = service.createPreferences({
        userId: 'user-1',
        email: { frequency: 'daily' },
      });

      expect(prefs.email.enabled).toBe(true);
      expect(prefs.email.frequency).toBe('daily');
      expect(prefs.email.categories).toHaveLength(5);
    });

    it('should respect explicit enabled=false', () => {
      const prefs = service.createPreferences({
        userId: 'user-1',
        email: { enabled: false },
      });

      expect(prefs.email.enabled).toBe(false);
    });

    it('should accept custom categories', () => {
      const prefs = service.createPreferences({
        userId: 'user-1',
        email: {
          categories: [
            { type: 'order_confirmation', enabled: true },
            { type: 'order_status_update', enabled: false },
          ],
        },
      });

      expect(prefs.email.categories).toHaveLength(2);
      expect(prefs.email.categories[1]?.enabled).toBe(false);
    });

    it('should throw if preferences already exist for user', () => {
      service.createPreferences({ userId: 'user-1' });

      expect(() => service.createPreferences({ userId: 'user-1' })).toThrow(
        'Preferences already exist for user: user-1',
      );
    });

    it('should generate sequential IDs', () => {
      const p1 = service.createPreferences({ userId: 'user-1' });
      const p2 = service.createPreferences({ userId: 'user-2' });

      expect(p1.id).toBe('pref-0001');
      expect(p2.id).toBe('pref-0002');
    });

    it('should not include SMS preferences when not provided', () => {
      const prefs = service.createPreferences({ userId: 'user-1' });
      expect(prefs.sms).toBeUndefined();
    });

    it('should not include webhook preferences when not provided', () => {
      const prefs = service.createPreferences({ userId: 'user-1' });
      expect(prefs.webhook).toBeUndefined();
    });

    it('should create SMS preferences when provided', () => {
      const prefs = service.createPreferences({
        userId: 'user-1',
        sms: { enabled: true, phoneNumber: '+1234567890' },
      });

      expect(prefs.sms).toBeDefined();
      expect(prefs.sms!.enabled).toBe(true);
      expect(prefs.sms!.phoneNumber).toBe('+1234567890');
      expect(prefs.sms!.categories).toHaveLength(5);
      expect(prefs.sms!.categories.every((c) => c.enabled)).toBe(true);
    });

    it('should default SMS to disabled when only phone number given', () => {
      const prefs = service.createPreferences({
        userId: 'user-1',
        sms: { phoneNumber: '+1234567890' },
      });

      expect(prefs.sms!.enabled).toBe(false);
      expect(prefs.sms!.phoneNumber).toBe('+1234567890');
    });

    it('should create webhook preferences when provided', () => {
      const prefs = service.createPreferences({
        userId: 'user-1',
        webhook: { enabled: true, url: 'https://example.com/hook' },
      });

      expect(prefs.webhook).toBeDefined();
      expect(prefs.webhook!.enabled).toBe(true);
      expect(prefs.webhook!.url).toBe('https://example.com/hook');
      expect(prefs.webhook!.categories).toHaveLength(5);
    });

    it('should create preferences with all three channels', () => {
      const prefs = service.createPreferences({
        userId: 'user-1',
        email: { frequency: 'daily' },
        sms: { enabled: true, phoneNumber: '+1234567890' },
        webhook: { enabled: true, url: 'https://example.com/hook' },
      });

      expect(prefs.email.frequency).toBe('daily');
      expect(prefs.sms!.enabled).toBe(true);
      expect(prefs.webhook!.enabled).toBe(true);
    });
  });

  describe('getPreferences', () => {
    it('should return undefined when no preferences exist', () => {
      expect(service.getPreferences('user-1')).toBeUndefined();
    });

    it('should return saved preferences', () => {
      service.createPreferences({ userId: 'user-1', email: { frequency: 'weekly' } });

      const prefs = service.getPreferences('user-1');
      expect(prefs).toBeDefined();
      expect(prefs!.email.frequency).toBe('weekly');
    });

    it('should return preferences with SMS and webhook settings', () => {
      service.createPreferences({
        userId: 'user-1',
        sms: { enabled: true, phoneNumber: '+1234567890' },
        webhook: { enabled: true, url: 'https://example.com/hook' },
      });

      const prefs = service.getPreferences('user-1');
      expect(prefs!.sms!.phoneNumber).toBe('+1234567890');
      expect(prefs!.webhook!.url).toBe('https://example.com/hook');
    });
  });

  describe('updatePreferences', () => {
    it('should update email enabled flag', () => {
      service.createPreferences({ userId: 'user-1' });

      const updated = service.updatePreferences('user-1', {
        email: { enabled: false },
      });

      expect(updated.email.enabled).toBe(false);
      expect(updated.email.frequency).toBe('immediate'); // unchanged
    });

    it('should update frequency', () => {
      service.createPreferences({ userId: 'user-1' });

      const updated = service.updatePreferences('user-1', {
        email: { frequency: 'daily' },
      });

      expect(updated.email.frequency).toBe('daily');
      expect(updated.email.enabled).toBe(true); // unchanged
    });

    it('should update categories', () => {
      service.createPreferences({ userId: 'user-1' });

      const updated = service.updatePreferences('user-1', {
        email: {
          categories: [
            { type: 'order_confirmation', enabled: false },
            { type: 'system_alert', enabled: true },
          ],
        },
      });

      expect(updated.email.categories).toHaveLength(2);
    });

    it('should throw if preferences do not exist', () => {
      expect(() =>
        service.updatePreferences('user-1', { email: { enabled: false } }),
      ).toThrow('Preferences not found for user: user-1');
    });

    it('should add SMS preferences via update', () => {
      service.createPreferences({ userId: 'user-1' });

      const updated = service.updatePreferences('user-1', {
        sms: { enabled: true, phoneNumber: '+1234567890' },
      });

      expect(updated.sms).toBeDefined();
      expect(updated.sms!.enabled).toBe(true);
      expect(updated.sms!.phoneNumber).toBe('+1234567890');
    });

    it('should add webhook preferences via update', () => {
      service.createPreferences({ userId: 'user-1' });

      const updated = service.updatePreferences('user-1', {
        webhook: { enabled: true, url: 'https://example.com/hook' },
      });

      expect(updated.webhook).toBeDefined();
      expect(updated.webhook!.enabled).toBe(true);
      expect(updated.webhook!.url).toBe('https://example.com/hook');
    });

    it('should preserve existing SMS preferences when updating email only', () => {
      service.createPreferences({
        userId: 'user-1',
        sms: { enabled: true, phoneNumber: '+1234567890' },
      });

      const updated = service.updatePreferences('user-1', {
        email: { frequency: 'daily' },
      });

      expect(updated.sms!.enabled).toBe(true);
      expect(updated.sms!.phoneNumber).toBe('+1234567890');
    });

    it('should update SMS phone number while preserving enabled state', () => {
      service.createPreferences({
        userId: 'user-1',
        sms: { enabled: true, phoneNumber: '+1234567890' },
      });

      const updated = service.updatePreferences('user-1', {
        sms: { phoneNumber: '+0987654321' },
      });

      expect(updated.sms!.enabled).toBe(true);
      expect(updated.sms!.phoneNumber).toBe('+0987654321');
    });
  });

  describe('deletePreferences', () => {
    it('should delete existing preferences', () => {
      service.createPreferences({ userId: 'user-1' });

      expect(service.deletePreferences('user-1')).toBe(true);
      expect(service.getPreferences('user-1')).toBeUndefined();
    });

    it('should return false if preferences do not exist', () => {
      expect(service.deletePreferences('user-1')).toBe(false);
    });
  });

  describe('shouldSendEmail', () => {
    it('should return true when no preferences exist (default behavior)', () => {
      expect(service.shouldSendEmail('user-1', 'order_confirmation')).toBe(true);
    });

    it('should return false when email is globally disabled', () => {
      service.createPreferences({
        userId: 'user-1',
        email: { enabled: false },
      });

      expect(service.shouldSendEmail('user-1', 'order_confirmation')).toBe(false);
    });

    it('should return false when category is disabled', () => {
      service.createPreferences({
        userId: 'user-1',
        email: {
          categories: [
            { type: 'order_confirmation', enabled: false },
            { type: 'order_status_update', enabled: true },
          ],
        },
      });

      expect(service.shouldSendEmail('user-1', 'order_confirmation')).toBe(false);
      expect(service.shouldSendEmail('user-1', 'order_status_update')).toBe(true);
    });

    it('should return true for unknown category (defaults to enabled)', () => {
      service.createPreferences({
        userId: 'user-1',
        email: {
          categories: [{ type: 'order_confirmation', enabled: true }],
        },
      });

      expect(service.shouldSendEmail('user-1', 'system_alert')).toBe(true);
    });

    it('should return true when email is enabled and category is enabled', () => {
      service.createPreferences({ userId: 'user-1' });

      expect(service.shouldSendEmail('user-1', 'order_confirmation')).toBe(true);
      expect(service.shouldSendEmail('user-1', 'system_alert')).toBe(true);
    });
  });

  describe('shouldSendSms', () => {
    it('should return false when no preferences exist (opt-in)', () => {
      expect(service.shouldSendSms('user-1', 'order_confirmation')).toBe(false);
    });

    it('should return false when preferences exist but no SMS config', () => {
      service.createPreferences({ userId: 'user-1' });
      expect(service.shouldSendSms('user-1', 'order_confirmation')).toBe(false);
    });

    it('should return false when SMS is disabled', () => {
      service.createPreferences({
        userId: 'user-1',
        sms: { enabled: false, phoneNumber: '+1234567890' },
      });

      expect(service.shouldSendSms('user-1', 'order_confirmation')).toBe(false);
    });

    it('should return true when SMS is enabled', () => {
      service.createPreferences({
        userId: 'user-1',
        sms: { enabled: true, phoneNumber: '+1234567890' },
      });

      expect(service.shouldSendSms('user-1', 'order_confirmation')).toBe(true);
    });

    it('should return false when SMS category is disabled', () => {
      service.createPreferences({
        userId: 'user-1',
        sms: {
          enabled: true,
          phoneNumber: '+1234567890',
          categories: [
            { type: 'order_confirmation', enabled: false },
            { type: 'order_status_update', enabled: true },
          ],
        },
      });

      expect(service.shouldSendSms('user-1', 'order_confirmation')).toBe(false);
      expect(service.shouldSendSms('user-1', 'order_status_update')).toBe(true);
    });
  });

  describe('shouldSendWebhook', () => {
    it('should return false when no preferences exist (opt-in)', () => {
      expect(service.shouldSendWebhook('user-1', 'order_confirmation')).toBe(false);
    });

    it('should return false when preferences exist but no webhook config', () => {
      service.createPreferences({ userId: 'user-1' });
      expect(service.shouldSendWebhook('user-1', 'order_confirmation')).toBe(false);
    });

    it('should return true when webhook is enabled', () => {
      service.createPreferences({
        userId: 'user-1',
        webhook: { enabled: true, url: 'https://example.com/hook' },
      });

      expect(service.shouldSendWebhook('user-1', 'order_confirmation')).toBe(true);
    });

    it('should return false when webhook category is disabled', () => {
      service.createPreferences({
        userId: 'user-1',
        webhook: {
          enabled: true,
          url: 'https://example.com/hook',
          categories: [{ type: 'order_confirmation', enabled: false }],
        },
      });

      expect(service.shouldSendWebhook('user-1', 'order_confirmation')).toBe(false);
    });
  });

  describe('shouldSendToChannel', () => {
    it('should delegate to email logic for email channel', () => {
      service.createPreferences({ userId: 'user-1', email: { enabled: false } });
      expect(service.shouldSendToChannel('user-1', 'email', 'order_confirmation')).toBe(false);
    });

    it('should delegate to sms logic for sms channel', () => {
      service.createPreferences({
        userId: 'user-1',
        sms: { enabled: true, phoneNumber: '+1234567890' },
      });
      expect(service.shouldSendToChannel('user-1', 'sms', 'order_confirmation')).toBe(true);
    });

    it('should delegate to webhook logic for webhook channel', () => {
      service.createPreferences({
        userId: 'user-1',
        webhook: { enabled: true, url: 'https://example.com/hook' },
      });
      expect(service.shouldSendToChannel('user-1', 'webhook', 'order_confirmation')).toBe(true);
    });

    it('should default to allow for in-app channel', () => {
      expect(service.shouldSendToChannel('user-1', 'in-app', 'order_confirmation')).toBe(true);
    });
  });

  describe('NotificationService integration', () => {
    let eventBus: EventBus;
    let notificationService: NotificationService;

    beforeEach(() => {
      eventBus = new EventBus();
      notificationService = new NotificationService(eventBus);
      notificationService.setPreferencesService(service);
      resetNotificationIdCounter();
    });

    it('should skip order confirmation when user has disabled it', async () => {
      service.createPreferences({
        userId: 'user-1',
        email: {
          categories: [
            { type: 'order_confirmation', enabled: false },
            { type: 'order_status_update', enabled: true },
          ],
        },
      });

      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      expect(notificationService.getNotificationCount()).toBe(0);
    });

    it('should skip status update when user has disabled email entirely', async () => {
      service.createPreferences({
        userId: 'user-1',
        email: { enabled: false },
      });

      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      expect(notificationService.getNotificationCount()).toBe(0);
    });

    it('should send notification when preferences allow it', async () => {
      service.createPreferences({ userId: 'user-1' }); // all defaults: enabled

      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
